import{_ as t,o as d,c as o,ag as a}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"MCP Tool Reference","description":"","frontmatter":{},"headers":[],"relativePath":"guide/mcp-api-tool-reference.md","filePath":"guide/mcp-api-tool-reference.md"}'),r={name:"guide/mcp-api-tool-reference.md"};function i(s,e,n,c,l,h){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="mcp-tool-reference" tabindex="-1">MCP Tool Reference <a class="header-anchor" href="#mcp-tool-reference" aria-label="Permalink to &quot;MCP Tool Reference&quot;">​</a></h1><p>This page provides the complete input schema and parameter details for every tool available through the TeamCentral MCP API. For an overview of tools and how to get started, see <a href="./mcp-api.html">MCP API</a>.</p><h2 id="data-models" tabindex="-1">Data Models <a class="header-anchor" href="#data-models" aria-label="Permalink to &quot;Data Models&quot;">​</a></h2><h3 id="get-data-models" tabindex="-1"><code>get_data_models</code> <a class="header-anchor" href="#get-data-models" aria-label="Permalink to &quot;`get_data_models`&quot;">​</a></h3><p>Returns a list of Data Models that have been configured.</p><p><strong>Parameters:</strong> None</p><hr><h3 id="get-data-model-properties" tabindex="-1"><code>get_data_model_properties</code> <a class="header-anchor" href="#get-data-model-properties" aria-label="Permalink to &quot;`get_data_model_properties`&quot;">​</a></h3><p>Gets the properties of a Data Model. Must first call <code>get_data_models</code> to get a <code>dataModelId</code>.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID from <code>get_data_models</code></td></tr></tbody></table><p><strong>References in the output:</strong> a property that is a tie to another entity has <code>dataType: &quot;Reference&quot;</code> and a <code>reference</code> object. Its <code>propertyName</code> is what you pass to <code>expand</code>, to a <code>reference</code> filter, or to a <code>reference</code> group key. The reference object includes:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>direction</code></td><td><code>Outbound</code> (this entity holds the foreign key to one related entity) or <code>Inbound</code> (other entities point back at this one — a derived collection)</td></tr><tr><td><code>cardinality</code></td><td><code>OneToOne</code> (single related entity) or <code>OneToMany</code> (a collection)</td></tr><tr><td><code>targetEntityType</code> / <code>targetEntitySubType</code></td><td>The related entity&#39;s type</td></tr><tr><td><code>targetDataModelId</code></td><td>The related Data Model&#39;s ID (for follow-up queries); may be <code>null</code> if the target has no Data Model</td></tr><tr><td><code>expandable</code></td><td>Whether you may load it inline — <code>false</code> when you lack access to the target model</td></tr><tr><td><code>derived</code></td><td><code>true</code> for Inbound collections (the reverse view of another entity&#39;s foreign key; read-only)</td></tr></tbody></table><p>See <a href="./mcp-api.html#working-with-related-data">Working with related data</a> for an overview.</p><h2 id="entity-lookup-query" tabindex="-1">Entity Lookup &amp; Query <a class="header-anchor" href="#entity-lookup-query" aria-label="Permalink to &quot;Entity Lookup &amp; Query&quot;">​</a></h2><h3 id="lookup-by-keyword" tabindex="-1"><code>lookup_by_keyword</code> <a class="header-anchor" href="#lookup-by-keyword" aria-label="Permalink to &quot;`lookup_by_keyword`&quot;">​</a></h3><p>Searches for foreign key-related entities by keyword. Must first call <code>get_data_models</code> to get an <code>entityType</code> and <code>entitySubType</code>, or get them from <code>get_data_model_properties</code>. If multiple entities are returned, the user should choose which one to use.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>searchValue</code></td><td>string</td><td>Yes</td><td>The keyword to search for</td></tr><tr><td><code>entityType</code></td><td>string</td><td>No</td><td>Entity type from <code>get_data_models</code></td></tr><tr><td><code>entitySubType</code></td><td>string</td><td>No</td><td>Entity sub-type from <code>get_data_models</code></td></tr><tr><td><code>limit</code></td><td>integer</td><td>No</td><td>Max results to return (1–100, default 10)</td></tr></tbody></table><hr><h3 id="query-entities" tabindex="-1"><code>query_entities</code> <a class="header-anchor" href="#query-entities" aria-label="Permalink to &quot;`query_entities`&quot;">​</a></h3><p>Queries for entities using filters, sorting, pagination, and optional property selection. This is the most flexible query tool, supporting complex filter groups with AND/OR logic and property-to-property comparisons.</p><p><strong>Prerequisites:</strong></p><ul><li>Call <code>get_data_models</code> to get a <code>dataModelId</code></li><li>Call <code>get_data_model_properties</code> to find valid property names for filters</li><li>Call <code>lookup_by_keyword</code> if a property is a foreign key, to get the entity ID (GUID) for comparison</li></ul><p>If results contain File entities with an <code>externalFileLocation</code> property, use <code>get_file_text</code> to extract readable content.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID from <code>get_data_models</code></td></tr><tr><td><code>queryParameterGroups</code></td><td>array</td><td>No</td><td>Filter groups (see <a href="#query-parameter-groups">Query Parameter Groups</a> below)</td></tr><tr><td><code>paging</code></td><td>object</td><td>No</td><td>Pagination settings (see <a href="#paging">Paging</a> below)</td></tr><tr><td><code>sortCondition</code></td><td>object</td><td>No</td><td>Sort settings (see <a href="#sort-condition">Sort Condition</a> below)</td></tr><tr><td><code>countOnly</code></td><td>boolean</td><td>No</td><td>When <code>true</code>, returns only the count without entity data (default <code>false</code>)</td></tr><tr><td><code>properties</code></td><td>string[]</td><td>No</td><td>Property names to include in results. Only these fields (plus <code>id</code>) are returned. Omit to return all fields.</td></tr><tr><td><code>expand</code></td><td>array</td><td>No</td><td>Related entities to load inline (see <a href="#references-and-expansion">References and expansion</a> below)</td></tr></tbody></table><h4 id="query-parameter-groups" tabindex="-1">Query Parameter Groups <a class="header-anchor" href="#query-parameter-groups" aria-label="Permalink to &quot;Query Parameter Groups&quot;">​</a></h4><p>Each group contains an array of filter parameters combined with AND/OR logic. Multiple groups are supported for complex queries.</p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>andOrOperator</code></td><td>enum</td><td>No</td><td><code>And</code> or <code>Or</code> (default <code>And</code>)</td></tr><tr><td><code>parameters</code></td><td>array</td><td>No</td><td>Array of filter parameters (see below)</td></tr></tbody></table><p><strong>Filter Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>operator</code></td><td>enum</td><td>Yes</td><td>One of: <code>EqualTo</code>, <code>NotEqualTo</code>, <code>GreaterThan</code>, <code>GreaterThanEqualTo</code>, <code>LessThan</code>, <code>LessThanEqualTo</code>, <code>Contains</code>, <code>StartsWith</code>, <code>NotStartsWith</code>, <code>EndsWith</code>, <code>NotEndsWith</code></td></tr><tr><td><code>propertyName</code></td><td>string</td><td>Yes</td><td>A valid property name from <code>get_data_model_properties</code></td></tr><tr><td><code>value</code></td><td>string</td><td>Conditional</td><td>The comparison value. For foreign key properties, provide the entity ID (GUID). Use the string <code>&quot;null&quot;</code> for null comparisons. Not required when <code>comparisonPropertyName</code> is set.</td></tr><tr><td><code>valueType</code></td><td>enum</td><td>Conditional</td><td><code>boolean</code>, <code>string</code>, <code>number</code>, or <code>null</code>. Use <code>null</code> when the value is null. Not required when <code>comparisonPropertyName</code> is set.</td></tr><tr><td><code>comparisonPropertyName</code></td><td>string</td><td>No</td><td>When set, compares <code>propertyName</code> against this property instead of <code>value</code>. Must be a valid property from <code>get_data_model_properties</code>.</td></tr><tr><td><code>reference</code></td><td>string</td><td>No</td><td>When set, the filter applies to a property of a <strong>related</strong> entity reached via this reference (a <code>Reference</code> property from <code>get_data_model_properties</code>). <code>propertyName</code> then names a property on the target entity.</td></tr><tr><td><code>match</code></td><td>enum</td><td>No</td><td>For an Inbound/OneToMany <code>reference</code> filter: <code>Any</code> (default) matches when at least one related entity satisfies the predicate (EXISTS). Ignored for Outbound/OneToOne references.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Filter on a related entity</p><p>To find Invoices whose related Customer is in a given industry, set <code>reference</code> to <code>Customer</code>, <code>propertyName</code> to <code>IndustryVertical</code>, <code>operator</code> to <code>EqualTo</code>, and <code>value</code> to the industry. For a OneToMany reference (e.g. Customers that have a large Invoice), set <code>match</code> to <code>Any</code>.</p></div><div class="tip custom-block"><p class="custom-block-title">Property-to-property comparison</p><p>To find records where one field exceeds another — for example, where <code>UpdatedDate</code> is after <code>CreatedDate</code> — set <code>propertyName</code> to <code>UpdatedDate</code>, <code>comparisonPropertyName</code> to <code>CreatedDate</code>, and <code>operator</code> to <code>GreaterThan</code>. When using <code>comparisonPropertyName</code>, omit <code>value</code> and <code>valueType</code>.</p></div><h4 id="paging" tabindex="-1">Paging <a class="header-anchor" href="#paging" aria-label="Permalink to &quot;Paging&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>pageNumber</code></td><td>integer</td><td>No</td><td>Page to retrieve, 1-based (default 1)</td></tr><tr><td><code>pageSize</code></td><td>integer</td><td>No</td><td>Items per page, 1–100 (default 25)</td></tr></tbody></table><p>The response includes <code>hasMore</code> (boolean) and <code>nextPage</code> (number or null). If <code>nextPage</code> is non-null, pass it as <code>pageNumber</code> in the next request to continue.</p><h4 id="sort-condition" tabindex="-1">Sort Condition <a class="header-anchor" href="#sort-condition" aria-label="Permalink to &quot;Sort Condition&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>propertyName</code></td><td>string</td><td>Yes</td><td>Property name from <code>get_data_model_properties</code></td></tr><tr><td><code>sortOrder</code></td><td>enum</td><td>No</td><td><code>Ascending</code> or <code>Descending</code> (default <code>Ascending</code>)</td></tr></tbody></table><h4 id="references-and-expansion" tabindex="-1">References and expansion <a class="header-anchor" href="#references-and-expansion" aria-label="Permalink to &quot;References and expansion&quot;">​</a></h4><p>The <code>expand</code> parameter loads related entities inline, returning an entity and its related data in one call. Each entry names a reference (from <code>get_data_model_properties</code>) and, optionally, which of its fields to return.</p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>reference</code></td><td>string</td><td>Yes</td><td>A reference name from <code>get_data_model_properties</code> (a property with <code>dataType: &quot;Reference&quot;</code>)</td></tr><tr><td><code>properties</code></td><td>string[]</td><td>No</td><td>Fields to return from the related entity. The related <code>id</code> is always included. Omit to return all fields.</td></tr></tbody></table><p>Expanded data is attached under <code>properties.expanded.&lt;referenceName&gt;</code> on each result:</p><ul><li><strong>Outbound / OneToOne</strong> → a single nested object (<code>null</code> when there is no related entity).</li><li><strong>Inbound / OneToMany</strong> → an array (<code>[]</code> when there are none).</li></ul><p>Expansion is <strong>shallow</strong> (expanded entities are not themselves expanded). A OneToMany expansion returns at most <strong>100</strong> related entities per parent; when capped, the parent carries an <code>ExpandedTruncated</code> marker listing the affected references — narrow with a filter or paging if you hit it.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;expanded&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;customer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Acme&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;region&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;APAC&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;invoice&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [ { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;transactionId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;616560&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;amountTotal&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1450</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;…&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } ]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><hr><h3 id="aggregate-entities" tabindex="-1"><code>aggregate_entities</code> <a class="header-anchor" href="#aggregate-entities" aria-label="Permalink to &quot;`aggregate_entities`&quot;">​</a></h3><p>Computes aggregate values — <code>Sum</code>, <code>Average</code>, <code>Count</code>, <code>Min</code>, <code>Max</code>, and <code>DistinctCount</code> — over a filtered set of entities, optionally grouped by one or more properties. Use this instead of paging through every record when you only need totals or per-group rollups.</p><p><strong>Prerequisites:</strong></p><ul><li>Call <code>get_data_models</code> to get a <code>dataModelId</code></li><li>Call <code>get_data_model_properties</code> to find valid property names for aggregations and grouping</li><li>Call <code>lookup_by_keyword</code> if filtering on a foreign key, to get the entity ID (GUID)</li></ul><p><code>Sum</code>, <code>Average</code>, <code>Min</code>, and <code>Max</code> require numeric properties (Int, Long, Double, or Decimal). <code>Count</code> counts matching rows and takes no property. <code>DistinctCount</code> counts distinct non-null values of a property.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID from <code>get_data_models</code></td></tr><tr><td><code>aggregations</code></td><td>array</td><td>Yes</td><td>One or more aggregates to compute (see <a href="#aggregations">Aggregations</a> below)</td></tr><tr><td><code>queryParameterGroups</code></td><td>array</td><td>No</td><td>Filter groups applied before aggregating — same shape as <code>query_entities</code> (see <a href="#query-parameter-groups">Query Parameter Groups</a> above)</td></tr><tr><td><code>groupBy</code></td><td>array</td><td>No</td><td>Group keys, each <code>{ propertyName, reference? }</code>. Omit for a single totals row; provide to get one row per distinct combination. Set <code>reference</code> to group by a property on a <strong>related</strong> entity (see <a href="#across-related-entities">Across related entities</a> below).</td></tr></tbody></table><h4 id="aggregations" tabindex="-1">Aggregations <a class="header-anchor" href="#aggregations" aria-label="Permalink to &quot;Aggregations&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>function</code></td><td>enum</td><td>Yes</td><td>One of: <code>Sum</code>, <code>Average</code>, <code>Count</code>, <code>Min</code>, <code>Max</code>, <code>DistinctCount</code></td></tr><tr><td><code>propertyName</code></td><td>string</td><td>Conditional</td><td>Property to aggregate. Required for all functions except <code>Count</code>. Must be numeric for <code>Sum</code>/<code>Average</code>/<code>Min</code>/<code>Max</code>.</td></tr><tr><td><code>alias</code></td><td>string</td><td>No</td><td>Output key for this value in the result. Defaults to <code>{function}_{propertyName}</code>. Result keys are returned camelCased (first letter lowercased), consistent with entity property keys — e.g. a <code>Sum</code> of <code>Amount</code> is returned under <code>sum_Amount</code>.</td></tr><tr><td><code>joinFilter</code></td><td>object</td><td>No</td><td>Count/aggregate only the base rows whose cross-entity condition holds — used for conditional ratios like On-Time % (see <a href="#conditional-cross-entity-aggregates-joinfilter">Conditional cross-entity aggregates</a> below)</td></tr></tbody></table><p><strong>Response:</strong></p><p>The response contains <code>matchedCount</code> (records matched by the filter), <code>groupByProperties</code>, and <code>rows</code>. Each row has a <code>groupKey</code> (the group&#39;s values, empty when not grouping) and <code>aggregates</code> (each alias mapped to its computed value).</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;matchedCount&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">14999</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;groupByProperties&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;WarehouseId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;rows&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;groupKey&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;warehouseId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;d5c3…&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;aggregates&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;sum_Amount&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">15599196.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;sum_Quantity&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32024</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Ratio KPIs</p><p>To compute a ratio such as &quot;cost per unit&quot;, request both the numerator and denominator in one call — for example, a <code>Sum</code> of cost and a <code>Sum</code> of units shipped — and divide the two returned totals. Add <code>groupBy</code> to break the ratio down per warehouse, product, region, and so on.</p></div><div class="warning custom-block"><p class="custom-block-title">Grouped queries</p><p>Grouped aggregations read the matching set to roll it up, so they are capped at a bounded number of records. If a grouped query matches too many records it is rejected — narrow the set with <code>queryParameterGroups</code> (for example, a date range). Ungrouped totals have no such limit.</p></div><h4 id="across-related-entities" tabindex="-1">Across related entities <a class="header-anchor" href="#across-related-entities" aria-label="Permalink to &quot;Across related entities&quot;">​</a></h4><ul><li><strong>Filter by a related property:</strong> <code>queryParameterGroups</code> accepts the same <code>reference</code> filters as <code>query_entities</code> — aggregate only the rows whose related entity matches (e.g. invoices whose Customer is in a given region).</li><li><strong>Group by a related property:</strong> set <code>reference</code> on a <code>groupBy</code> entry to roll up by a field on the related entity (e.g. invoice totals by Customer industry). The group-key label is <code>reference.propertyName</code> (first segment camelCased); rows with no related value fall into a <code>null</code> group rather than being dropped.</li><li><strong>OneToMany group keys fan out:</strong> grouping by an Inbound/OneToMany reference puts a row in each distinct related value (e.g. a customer appears under every opportunity stage it has); its measures are counted once per distinct value.</li></ul><h4 id="conditional-cross-entity-aggregates-joinfilter" tabindex="-1">Conditional cross-entity aggregates (<code>joinFilter</code>) <a class="header-anchor" href="#conditional-cross-entity-aggregates-joinfilter" aria-label="Permalink to &quot;Conditional cross-entity aggregates (`joinFilter`)&quot;">​</a></h4><p>A <code>joinFilter</code> on an aggregation clause includes a base row only when a condition against a <strong>joined</strong> entity holds. Put a <code>joinFilter</code> on one clause and leave another unconditional, then divide — the pattern for ratios like On-Time Shipment %.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>reference</code></td><td>string</td><td>Conditional</td><td>Named reference to the joined entity (preferred). Provide this <strong>or</strong> <code>entity</code> + <code>on</code>.</td></tr><tr><td><code>entity</code></td><td>string</td><td>Conditional</td><td>Explicit joined entity type (escape hatch); requires <code>on</code>.</td></tr><tr><td><code>on</code></td><td>object</td><td>Conditional</td><td>Explicit join keys <code>{ localProperty, foreignProperty }</code> (base foreign key → joined key), used with <code>entity</code>.</td></tr><tr><td><code>condition</code></td><td>object</td><td>Yes</td><td>The per-row test (below)</td></tr></tbody></table><p><strong>Condition:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>localProperty</code></td><td>string</td><td>Yes</td><td>Property on the base entity</td></tr><tr><td><code>operator</code></td><td>enum</td><td>Yes</td><td>Same operators as query filters</td></tr><tr><td><code>foreignProperty</code></td><td>string</td><td>Conditional</td><td>Property on the joined entity to compare against (cross-entity). Provide this <strong>or</strong> <code>value</code>.</td></tr><tr><td><code>value</code></td><td>string</td><td>Conditional</td><td>Literal to compare against. Provide this <strong>or</strong> <code>foreignProperty</code>.</td></tr></tbody></table><p>Example — On-Time Shipment %:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;aggregations&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;function&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Count&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;alias&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;total&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;function&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Count&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;alias&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on_time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;joinFilter&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;reference&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Customer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;condition&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;localProperty&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;DueDate&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;operator&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;LessThanEqualTo&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;foreignProperty&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RenewalDate&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } } }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Date comparisons</p><p>Ordering comparisons are typed off the <strong>base</strong> property: when it is a <code>Date</code> field, both sides compare chronologically. If the base property is a string, the comparison is lexicographic — reliable only for uniformly formatted ISO-8601 dates.</p></div><div class="warning custom-block"><p class="custom-block-title">Current limits</p><p><code>joinFilter</code> supports <strong>1-to-1</strong> joins only and cannot be combined with <code>groupBy</code> yet — request those separately. Aggregating over a related collection (e.g. summing a parent&#39;s child values) is not yet supported.</p></div><hr><h3 id="get-entities-by-ids" tabindex="-1"><code>get_entities_by_ids</code> <a class="header-anchor" href="#get-entities-by-ids" aria-label="Permalink to &quot;`get_entities_by_ids`&quot;">​</a></h3><p>Retrieves one or more entities by their unique IDs from a specific Data Model. For a single entity, pass an array with one ID. Non-existent IDs are silently omitted from the results.</p><p>If a result is a File entity with an <code>externalFileLocation</code> property, use <code>get_file_text</code> to extract readable content.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID from <code>get_data_models</code></td></tr><tr><td><code>entityIds</code></td><td>GUID[]</td><td>Yes</td><td>Array of entity IDs to retrieve (1–50)</td></tr><tr><td><code>properties</code></td><td>string[]</td><td>No</td><td>Property names to include in results. Only these fields (plus <code>id</code>) are returned. Omit to return all fields.</td></tr><tr><td><code>expand</code></td><td>array</td><td>No</td><td>Related entities to load inline — same shape as <a href="#references-and-expansion">References and expansion</a> on <code>query_entities</code></td></tr></tbody></table><h2 id="saved-queries" tabindex="-1">Saved Queries <a class="header-anchor" href="#saved-queries" aria-label="Permalink to &quot;Saved Queries&quot;">​</a></h2><h3 id="get-saved-queries" tabindex="-1"><code>get_saved_queries</code> <a class="header-anchor" href="#get-saved-queries" aria-label="Permalink to &quot;`get_saved_queries`&quot;">​</a></h3><p>Returns all Saved Queries (Live Data Providers) accessible to the user. Each query includes its name, ID, connector info, data model info, and declared input parameters.</p><p><strong>Parameters:</strong> None</p><hr><h3 id="get-saved-query-details" tabindex="-1"><code>get_saved_query_details</code> <a class="header-anchor" href="#get-saved-query-details" aria-label="Permalink to &quot;`get_saved_query_details`&quot;">​</a></h3><p>Returns detailed metadata for a specific Saved Query, including its mapped fields (property names, types, and descriptions) filtered by user permissions. Must first call <code>get_saved_queries</code> to get the <code>savedQueryId</code>.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>savedQueryId</code></td><td>GUID</td><td>Yes</td><td>The Saved Query ID from <code>get_saved_queries</code></td></tr></tbody></table><hr><h3 id="execute-saved-query" tabindex="-1"><code>execute_saved_query</code> <a class="header-anchor" href="#execute-saved-query" aria-label="Permalink to &quot;`execute_saved_query`&quot;">​</a></h3><p>Executes a Saved Query by its ID with the provided input parameters. Must first call <code>get_saved_queries</code> to get the <code>savedQueryId</code> and declared inputs.</p><p>If results contain File entities with an <code>externalFileLocation</code> property, use <code>get_file_text</code> to extract readable content.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>savedQueryId</code></td><td>GUID</td><td>Yes</td><td>The Saved Query ID from <code>get_saved_queries</code></td></tr><tr><td><code>inputs</code></td><td>array</td><td>No</td><td>Input parameters matching <code>DeclaredInputs</code> from <code>get_saved_queries</code> (see below)</td></tr><tr><td><code>properties</code></td><td>string[]</td><td>No</td><td>Property names to include in results. Only these fields (plus <code>id</code>) are returned. Omit to return all fields.</td></tr></tbody></table><p><strong>Input Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>key</code></td><td>string</td><td>Yes</td><td>Input name from <code>DeclaredInputs</code></td></tr><tr><td><code>value</code></td><td>string</td><td>Yes</td><td>Value for the input</td></tr></tbody></table><h2 id="data-entry" tabindex="-1">Data Entry <a class="header-anchor" href="#data-entry" aria-label="Permalink to &quot;Data Entry&quot;">​</a></h2><h3 id="get-data-entry-form" tabindex="-1"><code>get_data_entry_form</code> <a class="header-anchor" href="#get-data-entry-form" aria-label="Permalink to &quot;`get_data_entry_form`&quot;">​</a></h3><p>Retrieves a data entry form for a Data Model, optionally pre-populated with initial values. Must first call <code>get_data_models</code> to get a <code>dataModelId</code>. Send the output of this tool to <code>submit_data_entry_form</code> when complete.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID from <code>get_data_models</code></td></tr><tr><td><code>format</code></td><td>enum</td><td>Yes</td><td><code>AdaptiveCard</code> or <code>Json</code> — use the most appropriate format for the calling client</td></tr><tr><td><code>initialValues</code></td><td>array</td><td>No</td><td>Key-value pairs to pre-populate the form (see below)</td></tr></tbody></table><p><strong>Initial Values:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>key</code></td><td>string</td><td>Yes</td><td>Property name from <code>get_data_model_properties</code></td></tr><tr><td><code>value</code></td><td>string</td><td>Yes</td><td>Initial value for the field</td></tr></tbody></table><hr><h3 id="submit-data-entry-form" tabindex="-1"><code>submit_data_entry_form</code> <a class="header-anchor" href="#submit-data-entry-form" aria-label="Permalink to &quot;`submit_data_entry_form`&quot;">​</a></h3><p>Submits a completed data entry form to create or update a record.</p><div class="danger custom-block"><p class="custom-block-title">Destructive</p><p>This tool creates or modifies records. The AI assistant will confirm with the user before submitting.</p></div><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID — should match the one passed to <code>get_data_entry_form</code></td></tr><tr><td><code>system</code></td><td>enum</td><td>No</td><td>The submitting system: <code>Corbi</code>, <code>ChatGPT</code>, <code>Claude</code>, or <code>Copilot</code></td></tr><tr><td><code>formValues</code></td><td>array</td><td>Yes</td><td>Completed form values (see below)</td></tr></tbody></table><p><strong>Form Values:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>key</code></td><td>string</td><td>Yes</td><td>Property name from <code>get_data_model_properties</code></td></tr><tr><td><code>value</code></td><td>string</td><td>Yes</td><td>Submitted value for the field</td></tr></tbody></table><h2 id="file-extraction" tabindex="-1">File Extraction <a class="header-anchor" href="#file-extraction" aria-label="Permalink to &quot;File Extraction&quot;">​</a></h2><h3 id="get-file-text" tabindex="-1"><code>get_file_text</code> <a class="header-anchor" href="#get-file-text" aria-label="Permalink to &quot;`get_file_text`&quot;">​</a></h3><p>Extracts readable text from a document URL. Supports PDF, DOCX, PPTX, HTML, TXT, MD, CSV, JSON, and XML formats. Returns text in chunks — call repeatedly using the <code>nextOffset</code> value from the response until <code>hasMore</code> is <code>false</code>.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>url</code></td><td>URL</td><td>Yes</td><td>The <code>externalFileLocation</code> URL from the entity</td></tr><tr><td><code>offset</code></td><td>integer</td><td>No</td><td>Start at <code>0</code>, then use <code>nextOffset</code> from the previous response (default <code>0</code>)</td></tr></tbody></table>',115)])])}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
